#include <stdio.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int a,b,c;
        scanf("%d %d %d", &a, &b, &c);
        if(a==b && b==c) printf("Equilateral\n");
        else if(a==b || b==c || a==c) printf("Isosceles\n");
        else printf("Scalene\n");
    }
    return 0;
}

